+
+    #[test]
+    fn log_evicts_oldest_when_full() {
+        let mut log = DiagnosticLog::<TestEntry>::new().with_max_entries(2);
+        log.record(TestEntry {
+            kind: "a",
+            value: 1,
+        });
+        log.record(TestEntry {
